import { useState } from "react";

import AuthPage from "./pages/AuthPage";
import OnboardingPage from "./pages/OnboardingPage";
import DashboardPage from "./pages/DashboardPage";
import StudyWithFriendsPage from "./pages/StudyWithFriendsPage";
import SettingsPage from "./pages/SettingsPage";

function App() {
  const [page, setPage] = useState(1);
  const [aiSchedule, setAiSchedule] = useState(null);

  const handleLogout = () => {
    window.localStorage.removeItem("token");
    setPage(1);
    setAiSchedule(null);
  };
  const handleOpenSettings = () => setPage(5);

  const renderMainPage = () => {
    if (page === 2) {
      return (
        <OnboardingPage
          onNext={(scheduleData) => {
            setAiSchedule(scheduleData);
            setPage(3);
          }}
          onLogout={handleLogout}
        />
      );
    }

    if (page === 3) {
      return (
        <DashboardPage
          schedule={aiSchedule}
          onBack={() => setPage(2)}
          onGoToFriends={() => setPage(4)}
          onLogout={handleLogout}
          onSettings={handleOpenSettings}
        />
      );
    }

    if (page === 4) {
      return (
        <StudyWithFriendsPage
          onBack={() => setPage(3)}
          onLogout={handleLogout}
          onSettings={handleOpenSettings}
        />
      );
    }

    return <SettingsPage onLogout={handleLogout} onBack={() => setPage(3)} />;
  };

  return (
    <>
      {page === 1 && <AuthPage onNext={() => setPage(2)} />}

      {page !== 1 && (
        <div className="app-shell">
          <aside className="app-sidebar">
            <div>
              <div className="app-brand">Planly</div>
              <div className="app-sub">Ana Menü</div>
            </div>

            <div className="app-menu">
              <button
                className={`app-menu-item ${page === 3 ? "active" : ""}`}
                onClick={() => setPage(3)}
              >
                Program
              </button>
              <button
                className={`app-menu-item ${page === 2 ? "active" : ""}`}
                onClick={() => setPage(2)}
              >
                Sınav ve Konular
              </button>
              <button
                className={`app-menu-item ${page === 4 ? "active" : ""}`}
                onClick={() => setPage(4)}
              >
                Canlı Oda
              </button>
              <button
                className={`app-menu-item ${page === 5 ? "active" : ""}`}
                onClick={() => setPage(5)}
              >
                Kullanıcı Ayarları
              </button>
            </div>

            <button className="btn btn-danger" onClick={handleLogout}>
              Çıkış Yap
            </button>
          </aside>

          <main className="app-content">{renderMainPage()}</main>
        </div>
      )}
    </>
  );
}

export default App;
